    disputedOrUnconfirmedIssues: [],
    readinessAssessment:
      "The epic is ready for the orchestrator-owned final gate.",
    recommendedNextStep:
      "Run the final epic gate and review the synthesis evidence before closeout.",
    ...overrides,
  };
}

